SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption", sum(CASE WHEN (coalesce(bs."out.natural_gas.total.energy_consumption", 0) != 0) THEN 1 ELSE 0 END * bs.weight) AS "natural_gas.total.energy_consumption__nonzero_units_count" FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY 1 ORDER BY 1